  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import './ApprovalRow.scss';
  4	import {
  5	  ListPageBody,
  6	  RowFilter,
  7	  VirtualizedTable,
  8	  useListPageFilter,
  9	} from '@openshift-console/dynamic-plugin-sdk';
 10	import { ApprovalTaskKind } from '../../types';
 11	import {
 12	  getApprovalStatus,
 13	  getApprovalStatusInfo,
 14	  getPipelineRunOfApprovalTask,
 15	} from '../utils/pipeline-approval-utils';
 16	import { ApprovalStatus } from '../../types';
 17	import { useApprovalTasks, usePipelineRuns } from '../hooks/useTaskRuns';
 18	import { useParams } from 'react-router-dom-v5-compat';
 19	import useApprovalsColumns from './useApprovalsColumns';
 20	import ApprovalRow from './ApprovalRow';
 21	import { ListPageFilter } from '../list-pages/ListPageFilter';
 22	
 23	type ApprovalTasksListProps = {
 24	  namespace: string;
 25	  hideTextFilter?: boolean;
 26	};
 27	
 28	const pipelineApprovalFilterReducer = (obj: ApprovalTaskKind, pipelineRuns) => {
 29	  const pipelineRun = getPipelineRunOfApprovalTask(pipelineRuns, obj);
 30	  const status = getApprovalStatus(obj, pipelineRun);
 31	  if (
 32	    status === ApprovalStatus.PartiallyApproved ||
 33	    status === ApprovalStatus.AlmostApproved
 34	  ) {
 35	    return ApprovalStatus.RequestSent;
 36	  }
 37	  return status || ApprovalStatus.Unknown;
 38	};
 39	
 40	const ApprovalTasksList: React.FC<ApprovalTasksListProps> = ({
 41	  namespace,
 42	  hideTextFilter,
 43	}) => {
 44	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 45	  const { ns, name: pipelineRunName } = useParams();
 46	  namespace = namespace || ns;
 47	  const [pipelineRuns, pipelineRunsLoaded] = usePipelineRuns(namespace);
 48	  const [approvalTasks, approvalTasksLoaded, approvalTasksLoadError] =
 49	    useApprovalTasks(namespace, pipelineRunName);
 50	  const columns = useApprovalsColumns(namespace);
 51	
 52	  const filters: RowFilter<ApprovalTaskKind>[] = [
 53	    {
 54	      filterGroupName: t('Approval status'),
 55	      type: 'status',
 56	      items: [
 57	        {
 58	          id: ApprovalStatus.Accepted,
 59	          title: getApprovalStatusInfo(ApprovalStatus.Accepted).message,
 60	        },
 61	        {
 62	          id: ApprovalStatus.Rejected,
 63	          title: getApprovalStatusInfo(ApprovalStatus.Rejected).message,
 64	        },
 65	        {
 66	          id: ApprovalStatus.RequestSent,
 67	          title: getApprovalStatusInfo(ApprovalStatus.RequestSent).message,
 68	        },
 69	        {
 70	          id: ApprovalStatus.TimedOut,
 71	          title: getApprovalStatusInfo(ApprovalStatus.TimedOut).message,
 72	        },
 73	      ],
 74	      reducer: (obj: ApprovalTaskKind) =>
 75	        pipelineApprovalFilterReducer(obj, pipelineRuns),
 76	      filter: (filterValue, obj: ApprovalTaskKind) => {
 77	        const status = pipelineApprovalFilterReducer(obj, pipelineRuns);
 78	        return (
 79	          !filterValue.selected?.length ||
 80	          (status && filterValue.selected.includes(status))
 81	        );
 82	      },
 83	      ...(!pipelineRunName && {
 84	        defaultSelected: [ApprovalStatus.RequestSent],
 85	      }),
 86	    },
 87	  ];
 88	
 89	  const [data, filteredData, onFilterChange] = useListPageFilter(
 90	    approvalTasks,
 91	    filters,
 92	  );
 93	
 94	  return (
 95	    <>
 96	      <ListPageBody>
 97	        <ListPageFilter
 98	          columnLayout={{
 99	            columns: columns?.map(({ id, title }) => ({ id, title })),
100	            id: 'approvals-list',
101	            type: 'ApprovalTask',
102	            selectedColumns: new Set(['name']),
103	          }}
104	          rowFilters={filters}
105	          onFilterChange={onFilterChange}
106	          data={data}
107	          loaded={approvalTasksLoaded}
108	          hideColumnManagement
109	          hideNameLabelFilters={hideTextFilter}
110	        />
111	        <VirtualizedTable<ApprovalTaskKind>
112	          EmptyMsg={() => (
113	            <div className="cp-text-align-center" id="no-resource-msg">
114	              {t('No ApprovalTasks found')}
115	            </div>
116	          )}
117	          columns={columns}
118	          data={filteredData}
119	          loaded={approvalTasksLoaded}
120	          loadError={approvalTasksLoadError}
121	          Row={ApprovalRow}
122	          rowData={{
123	            pipelineRuns: pipelineRunsLoaded ? pipelineRuns : [],
124	          }}
125	          unfilteredData={data}
126	        />
127	      </ListPageBody>
128	    </>
129	  );
130	};
131	
132	export default ApprovalTasksList;

